import React, { useState, useEffect } from 'react';
import { Routes, Route, Link, useLocation } from 'react-router-dom';
import Navbar from '../components/Navbar';
import { adminAPI } from '../services/api';
import { toast } from 'react-toastify';

const AdminDashboard = () => {
  return (
    <div>
      <Navbar title="Admin Dashboard" />
      <div style={styles.container}>
        <Sidebar />
        <div style={styles.content}>
          <Routes>
            <Route path="/" element={<DashboardHome />} />
            <Route path="/employees" element={<ManageEmployees />} />
          </Routes>
        </div>
      </div>
    </div>
  );
};

const Sidebar = () => {
  const location = useLocation();
  
  const menuItems = [
    { path: '/admin', label: 'Dashboard', icon: '📊' },
    { path: '/admin/employees', label: 'Manage Employees', icon: '👥' },
  ];

  return (
    <div style={styles.sidebar}>
      {menuItems.map((item) => (
        <Link
          key={item.path}
          to={item.path}
          style={{
            ...styles.menuItem,
            backgroundColor: location.pathname === item.path ? '#9b59b6' : 'transparent',
            color: location.pathname === item.path ? 'white' : '#333',
          }}
        >
          <span>{item.icon}</span> {item.label}
        </Link>
      ))}
    </div>
  );
};

const DashboardHome = () => {
  const [stats, setStats] = useState({ employees: 0, company: null });

  useEffect(() => {
    loadStats();
  }, []);

  const loadStats = async () => {
    try {
      const [employeesRes, companyRes] = await Promise.all([
        adminAPI.getAllEmployees(),
        adminAPI.getMyCompany().catch(() => ({ data: null })),
      ]);
      setStats({
        employees: employeesRes.data.length,
        company: companyRes.data,
      });
    } catch (error) {
      toast.error('Failed to load statistics');
    }
  };

  return (
    <div>
      <h2 style={styles.pageTitle}>Dashboard Overview</h2>
      
      {stats.company && (
        <div style={styles.companyCard}>
          <h3>My Company</h3>
          <div style={styles.companyInfo}>
            {stats.company.logoUrl ? (
              <img 
                src={stats.company.logoUrl} 
                alt="Company Logo" 
                style={styles.companyLogo}
                onError={(e) => {
                  e.target.style.display = 'none';
                  e.target.nextSibling.style.display = 'flex';
                }}
              />
            ) : null}
            <div style={{
              ...styles.logoPlaceholder,
              display: stats.company.logoUrl ? 'none' : 'flex'
            }}>
              {stats.company.name.charAt(0).toUpperCase()}
            </div>
            <div>
              <h2 style={styles.companyName}>{stats.company.name}</h2>
              <p>{stats.company.address}</p>
              <p>{stats.company.phone} | {stats.company.email}</p>
            </div>
          </div>
        </div>
      )}

      <div style={styles.statsGrid}>
        <div style={{...styles.statCard, backgroundColor: '#9b59b6'}}>
          <h3 style={styles.statNumber}>{stats.employees}</h3>
          <p>Total Employees</p>
        </div>
      </div>
    </div>
  );
};

const ManageEmployees = () => {
  const [employees, setEmployees] = useState([]);
  const [myCompany, setMyCompany] = useState(null);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [formData, setFormData] = useState({
    username: '',
    password: '',
    email: '',
    fullName: '',
    role: 'HR',
    companyId: '',
    employeeCode: '',
    department: '',
    designation: '',
    dateOfJoining: '',
    dateOfBirth: '',
    phoneNumber: '',
    address: '',
    emergencyContact: '',
    salary: '',
  });
  const [phoneError, setPhoneError] = useState('');

  const roles = [
    'HR',
    'HR_MANAGER',
    'SOFTWARE_ENGINEER',
    'MANAGER',
    'GENERAL_MANAGER',
    'DEVELOPER',
  ];

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const [employeesRes, companyRes] = await Promise.all([
        adminAPI.getAllEmployees(),
        adminAPI.getMyCompany().catch(() => ({ data: null })),
      ]);
      setEmployees(employeesRes.data);
      setMyCompany(companyRes.data);
      if (companyRes.data) {
        setFormData(prev => ({ ...prev, companyId: companyRes.data.id }));
      }
    } catch (error) {
      toast.error('Failed to load data');
    }
  };

  const resetForm = () => {
    setFormData({
      username: '',
      password: '',
      email: '',
      fullName: '',
      role: 'HR',
      companyId: myCompany?.id || '',
      employeeCode: '',
      department: '',
      designation: '',
      dateOfJoining: '',
      dateOfBirth: '',
      phoneNumber: '',
      address: '',
      emergencyContact: '',
      salary: '',
    });
    setEditingId(null);
    setPhoneError('');
    setShowForm(false);
  };

  const validatePhone = (phone) => {
    if (!phone || phone.trim() === '') return true;
    const digitsOnly = phone.replace(/\D/g, '');
    return digitsOnly.length >= 10 && digitsOnly.length <= 15;
  };

  const handlePhoneChange = (e) => {
    const value = e.target.value;
    setFormData({ ...formData, phoneNumber: value });
    if (!validatePhone(value)) {
      setPhoneError('Phone number must be between 10-15 digits');
    } else {
      setPhoneError('');
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!validatePhone(formData.phoneNumber)) {
      toast.error('Phone number must be between 10-15 digits');
      return;
    }

    try {
      if (editingId) {
        await adminAPI.updateEmployee(editingId, {
          ...formData,
          salary: parseFloat(formData.salary) || 0,
        });
        toast.success('Employee updated successfully');
      } else {
        await adminAPI.createEmployee({
          ...formData,
          salary: parseFloat(formData.salary) || 0,
        });
        toast.success('Employee created successfully');
      }
      resetForm();
      loadData();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to save employee');
    }
  };

  const handleEdit = (emp) => {
    setFormData({
      username: emp.username,
      password: '',
      email: emp.email,
      fullName: emp.fullName,
      role: emp.role,
      companyId: emp.companyId,
      employeeCode: emp.employeeCode || '',
      department: emp.department || '',
      designation: emp.designation || '',
      dateOfJoining: emp.dateOfJoining || '',
      dateOfBirth: emp.dateOfBirth || '',
      phoneNumber: emp.phoneNumber || '',
      address: emp.address || '',
      emergencyContact: emp.emergencyContact || '',
      salary: emp.salary || '',
    });
    setEditingId(emp.id);
    setShowForm(true);
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this employee?')) return;
    try {
      await adminAPI.deleteEmployee(id);
      toast.success('Employee deleted successfully');
      loadData();
    } catch (error) {
      toast.error('Failed to delete employee');
    }
  };

  const handleInputChange = (field, value) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  return (
    <div>
      <div style={styles.header}>
        <h2 style={styles.pageTitle}>Manage Employees</h2>
        <button style={styles.addBtn} onClick={() => showForm ? resetForm() : setShowForm(true)}>
          {showForm ? 'Cancel' : '+ Add Employee'}
        </button>
      </div>

      {showForm && (
        <form onSubmit={handleSubmit} style={styles.formContainer}>
          <h3 style={styles.sectionTitle}>{editingId ? '✏️ Edit Employee' : '📋 Create Employee'}</h3>
          
          {/* Account Information */}
          <div style={styles.formSection}>
            <h4 style={styles.subSectionTitle}>👤 Account Information</h4>
            <div style={styles.formGrid}>
              <div style={styles.formField}>
                <label style={styles.label}>Username *</label>
                <input
                  type="text"
                  placeholder="Enter username"
                  value={formData.username}
                  onChange={(e) => handleInputChange('username', e.target.value)}
                  style={styles.input}
                  required
                />
              </div>
              
              <div style={styles.formField}>
                <label style={styles.label}>Password {editingId ? '(leave blank to keep unchanged)' : '*'}</label>
                <input
                  type="password"
                  placeholder={editingId ? "Leave blank to keep current" : "Enter password"}
                  value={formData.password}
                  onChange={(e) => handleInputChange('password', e.target.value)}
                  style={styles.input}
                  required={!editingId}
                />
              </div>
              
              <div style={styles.formField}>
                <label style={styles.label}>Email *</label>
                <input
                  type="email"
                  placeholder="Enter email address"
                  value={formData.email}
                  onChange={(e) => handleInputChange('email', e.target.value)}
                  style={styles.input}
                  required
                />
              </div>
              
              <div style={styles.formField}>
                <label style={styles.label}>Full Name *</label>
                <input
                  type="text"
                  placeholder="Enter full name"
                  value={formData.fullName}
                  onChange={(e) => handleInputChange('fullName', e.target.value)}
                  style={styles.input}
                  required
                />
              </div>
              
              <div style={styles.formField}>
                <label style={styles.label}>Role *</label>
                <select
                  value={formData.role}
                  onChange={(e) => handleInputChange('role', e.target.value)}
                  style={styles.input}
                  required
                >
                  {roles.map((role) => (
                    <option key={role} value={role}>{role.replace('_', ' ')}</option>
                  ))}
                </select>
              </div>
              
              <div style={styles.formField}>
                <label style={styles.label}>Company *</label>
                <input
                  type="text"
                  value={myCompany?.name || 'Loading...'}
                  style={{...styles.input, backgroundColor: '#e9ecef', cursor: 'not-allowed'}}
                  readOnly
                />
              </div>
            </div>
          </div>

          {/* Employment Details */}
          <div style={styles.formSection}>
            <h4 style={styles.subSectionTitle}>💼 Employment Details</h4>
            <div style={styles.formGrid}>
              <div style={styles.formField}>
                <label style={styles.label}>Employee Code</label>
                <input
                  type="text"
                  placeholder="e.g., EMP001"
                  value={formData.employeeCode}
                  onChange={(e) => handleInputChange('employeeCode', e.target.value)}
                  style={styles.input}
                />
              </div>
              
              <div style={styles.formField}>
                <label style={styles.label}>Department</label>
                <input
                  type="text"
                  placeholder="e.g., Engineering"
                  value={formData.department}
                  onChange={(e) => handleInputChange('department', e.target.value)}
                  style={styles.input}
                />
              </div>
              
              <div style={styles.formField}>
                <label style={styles.label}>Designation</label>
                <input
                  type="text"
                  placeholder="e.g., Software Developer"
                  value={formData.designation}
                  onChange={(e) => handleInputChange('designation', e.target.value)}
                  style={styles.input}
                />
              </div>
              
              <div style={styles.formField}>
                <label style={styles.label}>Date of Joining</label>
                <input
                  type="date"
                  value={formData.dateOfJoining}
                  onChange={(e) => handleInputChange('dateOfJoining', e.target.value)}
                  style={styles.input}
                />
              </div>
              
              <div style={styles.formField}>
                <label style={styles.label}>Salary (USD)</label>
                <input
                  type="number"
                  placeholder="e.g., 75000"
                  value={formData.salary}
                  onChange={(e) => handleInputChange('salary', e.target.value)}
                  style={styles.input}
                />
              </div>
            </div>
          </div>

          {/* Personal Information */}
          <div style={styles.formSection}>
            <h4 style={styles.subSectionTitle}>🏠 Personal Information</h4>
            <div style={styles.formGrid}>
              <div style={styles.formField}>
                <label style={styles.label}>Date of Birth</label>
                <input
                  type="date"
                  value={formData.dateOfBirth}
                  onChange={(e) => handleInputChange('dateOfBirth', e.target.value)}
                  style={styles.input}
                />
              </div>
              
              <div style={styles.formField}>
                <label style={styles.label}>Phone Number (10-15 digits)</label>
                <input
                  type="text"
                  placeholder="e.g., +1-555-123-4567"
                  value={formData.phoneNumber}
                  onChange={handlePhoneChange}
                  style={{...styles.input, borderColor: phoneError ? '#e74c3c' : undefined}}
                />
                {phoneError && <span style={styles.errorText}>{phoneError}</span>}
              </div>
              
              <div style={styles.formField}>
                <label style={styles.label}>Address</label>
                <input
                  type="text"
                  placeholder="Enter full address"
                  value={formData.address}
                  onChange={(e) => handleInputChange('address', e.target.value)}
                  style={styles.input}
                />
              </div>
              
              <div style={styles.formField}>
                <label style={styles.label}>Emergency Contact</label>
                <input
                  type="text"
                  placeholder="e.g., +1-555-999-0000"
                  value={formData.emergencyContact}
                  onChange={(e) => handleInputChange('emergencyContact', e.target.value)}
                  style={styles.input}
                />
              </div>
            </div>
          </div>

          <button type="submit" style={styles.submitBtn}>
            {editingId ? 'Update Employee' : 'Create Employee'}
          </button>
        </form>
      )}

      <div style={styles.tableContainer}>
        <table style={styles.table}>
          <thead>
            <tr>
              <th style={styles.th}>ID</th>
              <th style={styles.th}>Name</th>
              <th style={styles.th}>Username</th>
              <th style={styles.th}>Role</th>
              <th style={styles.th}>Department</th>
              <th style={styles.th}>Designation</th>
              <th style={styles.th}>Phone</th>
              <th style={styles.th}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {employees.map((emp) => (
              <tr key={emp.id} style={styles.tr}>
                <td style={styles.td}>{emp.id}</td>
                <td style={styles.td}>{emp.fullName}</td>
                <td style={styles.td}>{emp.username}</td>
                <td style={styles.td}>
                  <span style={styles.roleBadge}>{emp.role?.replace('_', ' ')}</span>
                </td>
                <td style={styles.td}>{emp.department || '-'}</td>
                <td style={styles.td}>{emp.designation || '-'}</td>
                <td style={styles.td}>{emp.phoneNumber || '-'}</td>
                <td style={styles.td}>
                  <button style={styles.editBtn} onClick={() => handleEdit(emp)}>Edit</button>
                  <button style={styles.deleteBtn} onClick={() => handleDelete(emp.id)}>Delete</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

const styles = {
  container: {
    display: 'flex',
    minHeight: 'calc(100vh - 70px)',
  },
  sidebar: {
    width: '250px',
    backgroundColor: '#f8f9fa',
    padding: '20px',
    borderRight: '1px solid #dee2e6',
  },
  menuItem: {
    display: 'block',
    padding: '12px 15px',
    borderRadius: '5px',
    textDecoration: 'none',
    marginBottom: '5px',
    transition: 'all 0.3s',
  },
  content: {
    flex: 1,
    padding: '30px',
    backgroundColor: '#f5f6fa',
  },
  pageTitle: {
    marginBottom: '20px',
    color: '#2c3e50',
  },
  companyCard: {
    backgroundColor: 'white',
    padding: '20px',
    borderRadius: '10px',
    marginBottom: '20px',
    boxShadow: '0 2px 5px rgba(0,0,0,0.1)',
  },
  companyInfo: {
    display: 'flex',
    alignItems: 'center',
    gap: '20px',
    marginTop: '15px',
  },
  companyLogo: {
    width: '80px',
    height: '80px',
    objectFit: 'contain',
    borderRadius: '10px',
    border: '1px solid #eee',
  },
  logoPlaceholder: {
    width: '80px',
    height: '80px',
    borderRadius: '10px',
    backgroundColor: '#9b59b6',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontSize: '32px',
    color: 'white',
    fontWeight: 'bold',
  },
  companyName: {
    margin: '0 0 10px 0',
    color: '#9b59b6',
  },
  statsGrid: {
    display: 'flex',
    gap: '20px',
  },
  statCard: {
    padding: '30px',
    borderRadius: '10px',
    color: 'white',
    minWidth: '200px',
    textAlign: 'center',
  },
  statNumber: {
    fontSize: '36px',
    margin: '0 0 10px 0',
  },
  header: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: '20px',
  },
  addBtn: {
    backgroundColor: '#9b59b6',
    color: 'white',
    border: 'none',
    padding: '10px 20px',
    borderRadius: '5px',
    cursor: 'pointer',
    fontSize: '14px',
    fontWeight: '600',
  },
  formContainer: {
    backgroundColor: 'white',
    padding: '30px',
    borderRadius: '12px',
    marginBottom: '25px',
    boxShadow: '0 4px 15px rgba(0,0,0,0.08)',
  },
  formSection: {
    marginBottom: '25px',
    paddingBottom: '20px',
    borderBottom: '1px solid #eee',
  },
  sectionTitle: {
    color: '#9b59b6',
    marginBottom: '20px',
    fontSize: '20px',
    fontWeight: '600',
  },
  subSectionTitle: {
    color: '#9b59b6',
    marginBottom: '15px',
    fontSize: '16px',
    fontWeight: '600',
  },
  formGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))',
    gap: '20px',
  },
  formField: {
    display: 'flex',
    flexDirection: 'column',
    gap: '6px',
  },
  label: {
    fontSize: '13px',
    fontWeight: '600',
    color: '#555',
    textTransform: 'uppercase',
    letterSpacing: '0.3px',
  },
  input: {
    padding: '12px 14px',
    border: '2px solid #e0e0e0',
    borderRadius: '8px',
    fontSize: '14px',
    transition: 'all 0.3s',
    outline: 'none',
    backgroundColor: '#fafafa',
  },
  errorText: {
    color: '#e74c3c',
    fontSize: '12px',
  },
  submitBtn: {
    backgroundColor: '#9b59b6',
    color: 'white',
    border: 'none',
    padding: '14px 30px',
    borderRadius: '8px',
    cursor: 'pointer',
    fontSize: '16px',
    fontWeight: '600',
    width: '100%',
    marginTop: '10px',
    boxShadow: '0 4px 10px rgba(155, 89, 182, 0.3)',
  },
  tableContainer: {
    backgroundColor: 'white',
    borderRadius: '12px',
    boxShadow: '0 4px 15px rgba(0,0,0,0.08)',
    overflow: 'hidden',
  },
  table: {
    width: '100%',
    borderCollapse: 'collapse',
  },
  th: {
    backgroundColor: '#8e44ad',
    color: 'white',
    padding: '15px',
    textAlign: 'left',
    fontSize: '13px',
    fontWeight: '600',
    textTransform: 'uppercase',
    letterSpacing: '0.5px',
  },
  tr: {
    borderBottom: '1px solid #eee',
    transition: 'background-color 0.2s',
  },
  td: {
    padding: '15px',
    fontSize: '14px',
    color: '#444',
  },
  roleBadge: {
    backgroundColor: '#e8daef',
    color: '#7d3c98',
    padding: '5px 12px',
    borderRadius: '20px',
    fontSize: '12px',
    fontWeight: '600',
    display: 'inline-block',
  },
  editBtn: {
    backgroundColor: '#f39c12',
    color: 'white',
    border: 'none',
    padding: '8px 16px',
    borderRadius: '6px',
    cursor: 'pointer',
    fontSize: '13px',
    fontWeight: '500',
    marginRight: '5px',
    transition: 'all 0.3s',
  },
  deleteBtn: {
    backgroundColor: '#e74c3c',
    color: 'white',
    border: 'none',
    padding: '8px 16px',
    borderRadius: '6px',
    cursor: 'pointer',
    fontSize: '13px',
    fontWeight: '500',
    transition: 'all 0.3s',
  },
};

export default AdminDashboard;
